sql:
SELECT SUM(amount_distributed) AS total_rewards
FROM reward_distributions
WHERE user_id = '0';

SELECT COUNT(*) 
FROM reward_tracking 
WHERE reward_category = 'engagement';

SELECT users.user_id, users.user_type, reward_tracking.total_to_receive
FROM users
INNER JOIN reward_tracking ON users.user_id = reward_tracking.user_id;

SELECT AVG(reward_count) AS average_rewards_per_user
FROM (
    SELECT user_id, COUNT(reward_id) AS reward_count
    FROM reward_distributions
    GROUP BY user_id
);

SELECT user_id, AVG(amount_distributed) AS average_reward_amount
FROM reward_distributions
GROUP BY user_id;

SELECT user_id, SUM(total_to_receive) AS total_rewards
FROM reward_tracking
GROUP BY user_id;

SELECT rd.distribution_id, rd.user_id, rd.reward_id, rd.date_distributed, rd.amount_distributed
FROM reward_distributions rd
WHERE rd.reward_id = 1;

SELECT u.user_identity, r.quant_reward
FROM users u
JOIN reward_tracking r ON u.user_id = r.user_id
WHERE r.quant_reward = (
    SELECT MAX(quant_reward) FROM reward_tracking
);

external_knowledge:
- "Identities" and "roles" refer to the unique identifiers and categorizations (e.g., basic, premium, moderator) of the users, respectively; 
- "Approved rewards" correspond to the total amount the user is eligible to receive, as indicated by the 'reward_status' being 'approved'; 
- "Last active" refers to the timestamp of when the user was last active on the platform.
